headStyles:
    * { margin: 0; padding: 0; box-sizing: border-box; }
    :root {
        --navy: #0f2233;
        --navy-deep: #0a1929;
        --navy-light: #132d44;
        --navy-card: rgba(19,45,68,0.5);
        --text-white: #ffffff;
        --text-soft: rgba(255,255,255,0.85);
        --text-dim: rgba(255,255,255,0.6);
        --text-faint: rgba(255,255,255,0.4);
        --accent: #73d7ee;
        --action-blue: #004dff;
        --purple: #750787;
        --pink: #ffafc8;
        --red: #e40303;
        --orange: #ff8c00;
        --yellow: #ffed00;
        --green: #008026;
        --border: rgba(255,255,255,0.08);
        --rainbow: linear-gradient(90deg, #e40303 0%, #ff8c00 17%, #ffed00 33%, #008026 50%, #004dff 67%, #750787 84%, #e40303 100%);
        --shadow-md: 0 4px 16px rgba(0,0,0,0.4);
        --transition: all 0.3s ease;
    }

@keyframes prideShimmer {
    0%   { background-position: 0% 50%; }
    100% { background-position: 200% 50%; }
}
@keyframes float {
    0%, 100% { transform: translateY(0); }
    50% { transform: translateY(-6px); }
}
@keyframes fadeInUp {
    from { opacity: 0; transform: translateY(20px); }
    to { opacity: 1; transform: translateY(0); }
}
@keyframes glow {
    0%, 100% { box-shadow: 0 0 20px rgba(115,215,238,0.15); }
    50% { box-shadow: 0 0 40px rgba(115,215,238,0.35); }
}
@keyframes pulseDot {
    0%, 100% { opacity: 1; transform: scale(1); }
    50% { opacity: 0.6; transform: scale(1.15); }
}
@keyframes marquee {
    from { transform: translateX(0); }
    to { transform: translateX(-50%); }
}
@keyframes confettiDrift {
    0%   { transform: translateY(-10vh) rotate(0deg); opacity: 0; }
    10%  { opacity: 0.9; }
    100% { transform: translateY(110vh) rotate(720deg); opacity: 0; }
}
html { scroll-behavior: smooth; }
body { font-family: 'Roboto Slab', Georgia, serif; background-color: var(--navy); color: var(--text-white); line-height: 1.6; overflow-x: hidden; }
a { color: inherit; text-decoration: none; }

/* Confetti backdrop */
.confetti-layer {
    position: absolute;
    top: 0; left: 0; right: 0;
    height: 700px;
    pointer-events: none;
    overflow: hidden;
    z-index: 0;
}
.confetti-piece {
    position: absolute;
    top: 0;
    width: 8px;
    height: 14px;
    opacity: 0;
    animation: confettiDrift linear infinite;
}

/* Hero */
.hero {
    position: relative;
    padding: 5rem 2rem 4rem;
    text-align: center;
    max-width: 900px;
    margin: 0 auto;
    overflow: hidden;
}
.hero::before {
    content: '';
    position: absolute;
    top: -100px;
    left: 50%;
    transform: translateX(-50%);
    width: 600px;
    height: 600px;
    background: radial-gradient(circle, rgba(115,215,238,0.12) 0%, rgba(117,7,135,0.06) 40%, transparent 70%);
    border-radius: 50%;
    pointer-events: none;
    z-index: 0;
}
.hero > * { position: relative; z-index: 1; }
.save-the-date-badge {
    display: inline-flex;
    align-items: center;
    gap: 0.5rem;
    padding: 0.5rem 1.25rem;
    background: rgba(115,215,238,0.1);
    border: 1px solid rgba(115,215,238,0.3);
    border-radius: 100px;
    font-family: 'Montserrat', Arial, sans-serif;
    font-size: 0.75rem;
    text-transform: uppercase;
    letter-spacing: 2px;
    color: var(--accent);
    font-weight: 700;
    margin-bottom: 1.5rem;
    animation: fadeInUp 0.6s ease-out;
}
.save-the-date-badge .dot {
    width: 8px;
    height: 8px;
    border-radius: 50%;
    background: var(--accent);
    animation: pulseDot 2s ease-in-out infinite;
}
.hero h1 {
    font-family: 'Montserrat', Arial, sans-serif;
    font-size: clamp(2.5rem, 7vw, 4.5rem);
    line-height: 1.05;
    margin-bottom: 1rem;
    font-weight: 900;
    letter-spacing: -1.5px;
    animation: fadeInUp 0.8s ease-out;
}
.hero h1 .rainbow-word {
    background: var(--rainbow);
    background-size: 200% 100%;
    animation: prideShimmer 6s linear infinite;
    -webkit-background-clip: text;
    background-clip: text;
    color: transparent;
}
.hero-tagline {
    font-family: 'Montserrat', Arial, sans-serif;
    font-size: clamp(1rem, 2.2vw, 1.25rem);
    color: var(--text-soft);
    max-width: 640px;
    margin: 0 auto 2rem;
    font-weight: 400;
    line-height: 1.55;
    animation: fadeInUp 1s ease-out;
}
.hero-divider {
    width: 100px;
    height: 4px;
    background: var(--rainbow);
    background-size: 200% 100%;
    animation: prideShimmer 4s linear infinite;
    margin: 0 auto;
    border-radius: 2px;
}

/* Marquee strip */
.marquee-strip {
    background: var(--navy-deep);
    border-top: 1px solid var(--border);
    border-bottom: 1px solid var(--border);
    padding: 1rem 0;
    overflow: hidden;
    white-space: nowrap;
}
.marquee-track {
    display: inline-block;
    animation: marquee 40s linear infinite;
    font-family: 'Montserrat', Arial, sans-serif;
    font-weight: 700;
    font-size: 1rem;
    text-transform: uppercase;
    letter-spacing: 3px;
}
.marquee-track span { color: var(--text-dim); padding: 0 1.5rem; }
.marquee-track .star { color: var(--accent); }

/* Event details (3-card layout: date / time / location) */
.event-details {
    max-width: 1000px;
    margin: 4rem auto 0;
    padding: 0 2rem;
}
.detail-grid {
    display: grid;
    grid-template-columns: repeat(3, 1fr);
    gap: 1rem;
    margin-bottom: 3rem;
}
.detail-card {
    border: 1px solid var(--border);
    border-radius: 12px;
    padding: 1.75rem 1rem;
    text-align: center;
    background: var(--navy-card);
    position: relative;
    overflow: hidden;
    transition: var(--transition);
}
.detail-card:hover {
    transform: translateY(-4px);
    border-color: rgba(115,215,238,0.3);
}
.detail-card::before {
    content: '';
    position: absolute;
    top: 0;
    left: 0;
    right: 0;
    height: 3px;
    background: var(--rainbow);
    background-size: 200% 100%;
    animation: prideShimmer 4s linear infinite;
}
.detail-card .icon { font-size: 1.75rem; margin-bottom: 0.5rem; display: block; }
.detail-card .label {
    font-family: 'Montserrat', Arial, sans-serif;
    font-size: 0.65rem;
    text-transform: uppercase;
    letter-spacing: 2px;
    color: var(--accent);
    margin-bottom: 0.4rem;
    font-weight: 700;
}
.detail-card .value {
    font-family: 'Montserrat', Arial, sans-serif;
    font-size: 1.1rem;
    font-weight: 700;
    line-height: 1.3;
}
.detail-card .sub {
    font-family: 'Montserrat', Arial, sans-serif;
    font-size: 0.8rem;
    color: var(--text-dim);
    margin-top: 0.35rem;
    font-weight: 400;
}
@media (max-width: 720px) {
    .detail-grid { grid-template-columns: 1fr; }
}

/* Section header */
.section-header { text-align: center; max-width: 720px; margin: 0 auto 2rem; }
.section-eyebrow {
    font-family: 'Montserrat', Arial, sans-serif;
    font-size: 0.75rem;
    text-transform: uppercase;
    letter-spacing: 3px;
    color: var(--accent);
    font-weight: 700;
    margin-bottom: 0.75rem;
}
.section-header h2 {
    font-family: 'Montserrat', Arial, sans-serif;
    font-size: clamp(1.75rem, 4vw, 2.5rem);
    line-height: 1.15;
    margin-bottom: 1rem;
    font-weight: 800;
    letter-spacing: -0.5px;
}
.section-header p { color: var(--text-soft); font-size: 1.05rem; line-height: 1.7; }

/* Harvey Milk tribute section */
.milk-section {
    max-width: 900px;
    margin: 5rem auto;
    padding: 0 2rem;
}
.milk-card {
    border: 1px solid var(--border);
    border-radius: 16px;
    padding: 3rem 2.5rem;
    background: linear-gradient(135deg, rgba(19,45,68,0.7) 0%, rgba(117,7,135,0.18) 100%);
    position: relative;
    overflow: hidden;
    text-align: center;
}
.milk-card::before {
    content: '';
    position: absolute;
    top: 0;
    left: 0;
    right: 0;
    height: 4px;
    background: var(--rainbow);
    background-size: 200% 100%;
    animation: prideShimmer 4s linear infinite;
}
.milk-eyebrow {
    font-family: 'Montserrat', Arial, sans-serif;
    font-size: 0.75rem;
    text-transform: uppercase;
    letter-spacing: 3px;
    color: var(--accent);
    font-weight: 700;
    margin-bottom: 1rem;
}
.milk-card h2 {
    font-family: 'Montserrat', Arial, sans-serif;
    font-size: clamp(1.6rem, 3.5vw, 2.1rem);
    font-weight: 800;
    margin-bottom: 1.25rem;
    letter-spacing: -0.3px;
}
.milk-quote {
    font-family: 'Roboto Slab', Georgia, serif;
    font-size: clamp(1.4rem, 3.2vw, 1.85rem);
    line-height: 1.4;
    font-style: italic;
    color: var(--text-white);
    margin: 1.5rem auto 1rem;
    max-width: 640px;
}
.milk-attr {
    font-family: 'Montserrat', Arial, sans-serif;
    font-size: 0.85rem;
    color: var(--accent);
    text-transform: uppercase;
    letter-spacing: 2px;
    font-weight: 700;
    margin-bottom: 1.75rem;
}
.milk-context {
    color: var(--text-soft);
    font-size: 1rem;
    line-height: 1.75;
    max-width: 640px;
    margin: 0 auto;
    text-align: left;
}
.milk-context p { margin-bottom: 1rem; }
.milk-context p:last-child { margin-bottom: 0; }

/* What to expect */
.what-section { max-width: 1000px; margin: 5rem auto; padding: 0 2rem; }
.what-grid { display: grid; grid-template-columns: repeat(3, 1fr); gap: 1.5rem; }
.what-card {
    border: 1px solid var(--border);
    border-radius: 12px;
    padding: 2rem 1.5rem;
    background: var(--navy-card);
    transition: var(--transition);
}
.what-card:hover {
    transform: translateY(-4px);
    border-color: rgba(115,215,238,0.25);
    background: rgba(19,45,68,0.7);
}
.what-icon { font-size: 2rem; margin-bottom: 1rem; }
.what-card h3 {
    font-family: 'Montserrat', Arial, sans-serif;
    font-size: 1.15rem;
    font-weight: 700;
    margin-bottom: 0.75rem;
}
.what-card p { color: var(--text-soft); font-size: 0.95rem; line-height: 1.65; }
@media (max-width: 800px) { .what-grid { grid-template-columns: 1fr; } }

/* Why this moment */
.why-section {
    background: linear-gradient(180deg, transparent 0%, rgba(117,7,135,0.08) 50%, transparent 100%);
    padding: 5rem 2rem;
    margin: 3rem 0;
}
.why-inner { max-width: 800px; margin: 0 auto; text-align: center; }
.why-context { color: var(--text-soft); font-size: 1rem; line-height: 1.8; text-align: left; margin-top: 1.5rem; }
.why-context p { margin-bottom: 1rem; }
.why-context p:last-child { margin-bottom: 0; }

/* RSVP Form */
.rsvp-section { max-width: 600px; margin: 5rem auto 4rem; padding: 0 2rem; }
.rsvp-card {
    border: 1px solid var(--border);
    border-radius: 16px;
    padding: 2.5rem;
    background: var(--navy-card);
    position: relative;
    overflow: hidden;
    animation: glow 4s ease-in-out infinite;
}
.rsvp-card::before {
    content: '';
    position: absolute;
    top: 0;
    left: 0;
    right: 0;
    height: 4px;
    background: var(--rainbow);
    background-size: 200% 100%;
    animation: prideShimmer 4s linear infinite;
}
.rsvp-eyebrow {
    font-family: 'Montserrat', Arial, sans-serif;
    font-size: 0.7rem;
    text-transform: uppercase;
    letter-spacing: 2.5px;
    color: var(--accent);
    font-weight: 700;
    text-align: center;
    margin-bottom: 0.5rem;
}
.rsvp-card h2 {
    font-family: 'Montserrat', Arial, sans-serif;
    font-size: 1.75rem;
    margin-bottom: 0.5rem;
    text-align: center;
    font-weight: 800;
    letter-spacing: -0.3px;
}
.rsvp-subtitle {
    color: var(--text-soft);
    font-family: 'Montserrat', Arial, sans-serif;
    font-size: 0.95rem;
    text-align: center;
    margin-bottom: 2rem;
}
.form-row { display: grid; grid-template-columns: 1fr 1fr; gap: 1rem; margin-bottom: 1rem; }
.form-row.full { grid-template-columns: 1fr; }
@media (max-width: 500px) { .form-row { grid-template-columns: 1fr; } }
.form-group { display: flex; flex-direction: column; }
.form-group label {
    font-family: 'Montserrat', Arial, sans-serif;
    font-size: 0.7rem;
    text-transform: uppercase;
    letter-spacing: 1.5px;
    color: var(--accent);
    margin-bottom: 0.4rem;
    font-weight: 700;
}
.form-group input {
    background: rgba(255,255,255,0.06);
    border: 1px solid var(--border);
    border-radius: 8px;
    padding: 0.85rem 1rem;
    color: var(--text-white);
    font-size: 1rem;
    font-family: 'Roboto Slab', Georgia, serif;
    transition: var(--transition);
}
.form-group input:focus {
    outline: none;
    border-color: var(--accent);
    background: rgba(115,215,238,0.05);
}
.form-group input::placeholder { color: rgba(255,255,255,0.25); }
.btn {
    font-family: 'Montserrat', Arial, sans-serif;
    padding: 0.875rem 2rem;
    border-radius: 8px;
    font-weight: 700;
    font-size: 0.95rem;
    transition: var(--transition);
    border: none;
    cursor: pointer;
    display: inline-block;
    text-align: center;
    letter-spacing: 0.3px;
}
.btn-submit {
    background: var(--action-blue);
    color: #ffffff;
    width: 100%;
    margin-top: 0.75rem;
    font-size: 1.05rem;
    padding: 1.1rem;
    text-transform: uppercase;
    letter-spacing: 1.5px;
}
.btn-submit:hover {
    transform: translateY(-2px);
    box-shadow: 0 8px 30px rgba(0,77,255,0.4);
    background: #0040d9;
}
.btn-submit:disabled { opacity: 0.5; cursor: not-allowed; transform: none; }

/* Success */
.success-message { display: none; text-align: center; padding: 2rem 0; }
.success-message .check {
    font-size: 3.5rem;
    margin-bottom: 1rem;
    color: var(--accent);
    animation: float 3s ease-in-out infinite;
}
.success-message h3 {
    font-family: 'Montserrat', Arial, sans-serif;
    font-size: 1.5rem;
    margin-bottom: 0.75rem;
    font-weight: 800;
}
.success-message p { color: var(--text-soft); line-height: 1.7; }
.success-share {
    margin-top: 1.5rem;
    padding-top: 1.5rem;
    border-top: 1px solid var(--border);
}
.success-share p {
    font-family: 'Montserrat', Arial, sans-serif;
    font-size: 0.85rem;
    color: var(--text-dim);
    margin-bottom: 0.75rem;
}
.share-buttons { display: flex; gap: 0.5rem; justify-content: center; flex-wrap: wrap; }
.share-btn {
    font-family: 'Montserrat', Arial, sans-serif;
    font-size: 0.8rem;
    padding: 0.5rem 1rem;
    border: 1px solid var(--border);
    border-radius: 6px;
    color: var(--text-soft);
    transition: var(--transition);
    font-weight: 600;
}
.share-btn:hover { border-color: var(--accent); color: var(--accent); }

/* Founding nudge */
.founding-nudge { max-width: 600px; margin: 0 auto; padding: 0 2rem 5rem; text-align: center; }
.nudge-card {
    border: 1px solid var(--border);
    border-radius: 16px;
    padding: 2.5rem;
    background: linear-gradient(135deg, rgba(19,45,68,0.7) 0%, rgba(117,7,135,0.15) 100%);
    position: relative;
    overflow: hidden;
}
.nudge-card::before {
    content: '';
    position: absolute;
    top: 0;
    left: 0;
    right: 0;
    height: 3px;
    background: var(--rainbow);
    background-size: 200% 100%;
    animation: prideShimmer 4s linear infinite;
}
.nudge-card .stonewall-num {
    font-family: 'Montserrat', Arial, sans-serif;
    font-size: 3rem;
    font-weight: 900;
    background: var(--rainbow);
    background-size: 200% 100%;
    animation: prideShimmer 6s linear infinite;
    -webkit-background-clip: text;
    background-clip: text;
    color: transparent;
    line-height: 1;
    margin-bottom: 0.5rem;
}
.nudge-card .stonewall-label {
    font-family: 'Montserrat', Arial, sans-serif;
    font-size: 0.75rem;
    text-transform: uppercase;
    letter-spacing: 2px;
    color: var(--accent);
    font-weight: 700;
    margin-bottom: 1rem;
}
.nudge-card h3 {
    font-family: 'Montserrat', Arial, sans-serif;
    font-size: 1.4rem;
    margin-bottom: 0.75rem;
    font-weight: 800;
}
.nudge-card p {
    color: var(--text-soft);
    margin-bottom: 1.5rem;
    font-size: 0.95rem;
    line-height: 1.7;
}
.btn-outline {
    font-family: 'Montserrat', Arial, sans-serif;
    background: transparent;
    color: var(--text-white);
    border: 2px solid var(--accent);
    padding: 0.85rem 2rem;
    border-radius: 8px;
    font-weight: 700;
    font-size: 0.95rem;
    transition: var(--transition);
    display: inline-block;
    letter-spacing: 0.5px;
    text-transform: uppercase;
}
.btn-outline:hover {
    background: var(--accent);
    color: var(--navy);
    transform: translateY(-2px);
}

/* Mobile tweaks */
@media (max-width: 768px) {
    .hero { padding: 3.5rem 1.5rem 2.5rem; }
    .event-details, .rsvp-section, .founding-nudge, .what-section, .milk-section { padding-left: 1.5rem; padding-right: 1.5rem; }
    .rsvp-card, .nudge-card { padding: 2rem 1.5rem; }
    .milk-card { padding: 2.25rem 1.5rem; }
    .why-section { padding: 3.5rem 1.5rem; }
}

