/* Confetti backdrop in Pride colors. Decorative only, respects reduced motion. */
(function () {
    var prefersReduced = window.matchMedia && window.matchMedia('(prefers-reduced-motion: reduce)').matches;
    if (prefersReduced) return;
    var layer = document.getElementById('confettiLayer');
    if (!layer) return;
    var colors = ['#e40303', '#ff8c00', '#ffed00', '#008026', '#004dff', '#750787', '#73d7ee', '#ffafc8'];
    var pieces = 28;
    for (var i = 0; i < pieces; i++) {
        var p = document.createElement('span');
        p.className = 'confetti-piece';
        p.style.left = (Math.random() * 100) + '%';
        p.style.background = colors[i % colors.length];
        p.style.animationDuration = (8 + Math.random() * 8) + 's';
        p.style.animationDelay = (Math.random() * 8) + 's';
        p.style.transform = 'rotate(' + (Math.random() * 360) + 'deg)';
        if (Math.random() > 0.5) { p.style.borderRadius = '50%'; p.style.width = '10px'; p.style.height = '10px'; }
        layer.appendChild(p);
    }
})();
